{% extends '@PrestaShop/Admin/layout.html.twig' %}

{% block content %}
{% endblock %}

{% block javascripts %}
  <script type=\"text/javascript\">
    {# Script dedicated to close fancyboxes used to display this form
     in \"Create an order\" and \"View an order\" pages #}

    // legacy behavior
    if (typeof window.parent.getSummary !== \"undefined\") {
      window.parent.getSummary();
    }

    // symfony behavior
    if (typeof window.parent.order_create !== \"undefined\") {
      window.parent.order_create.refreshAddressesList({{ refreshCartAddresses }});
    }
    if (typeof window.parent.order_view !== \"undefined\") {
      window.parent.location.reload();
    }

    window.parent.\$.fancybox.close();
  </script>
{% endblock %}
